{
  "name": "CEPHLODYNE_APP_NAME-frontend",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "devDependencies": {
    "@bufbuild/protoc-gen-es": "^{{PROTOBUF_VERSION}}",
    "@connectrpc/protoc-gen-connect-es": "^{{CONNECT_WEB_VERSION}}",
    "@sveltejs/vite-plugin-svelte": "^6.2.0",
    "svelte": "^{{SVELTE_VERSION}}",
    "svelte-check": "^4.3.1",
    "typescript": "^5.5.0",
    "vite": "^{{VITE_VERSION}}"
  },
  "dependencies": {
    "@bufbuild/protobuf": "^{{PROTOBUF_VERSION}}",
    "@connectrpc/connect": "^{{CONNECT_WEB_VERSION}}",
