import { defineConfig, loadEnv } from 'vite'
import { svelte } from '@sveltejs/vite-plugin-svelte'

export default defineConfig(({ mode }) => {
  const env = loadEnv(mode, process.cwd(), '')
  const apiPort = env.API_PORT || '8080'

  return {
    plugins: [svelte()],
    server: {
      proxy: {
        '^/.*Service/.*': {
          target: `http://127.0.0.1:${apiPort}`,
          changeOrigin: true,
        }
      }
    }
  }
})


import App from './App.svelte'

const app = new App({
  target: document.getElementById('app')!,
})

export default app


syntax = "proto3";
package ping.v1;

option go_package = "CEPHLODYNE_APP_NAME/internal/gen/ping/v1;pingv1";

service PingService {
  rpc Ping (PingRequest) returns (PingResponse) {}
}

message PingRequest {
  string name = 1;
}

message PingResponse {
  string message = 1;
}


package main

import (
	"embed"
	"io/fs"
	"net/http"

	"github.com/cephlodyne/kit/ev"
	"github.com/cephlodyne/kit/jot"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"

	"CEPHLODYNE_APP_NAME/internal/ping"
	pingv1connect "CEPHLODYNE_APP_NAME/internal/gen/ping/v1/pingv1connect"
)

//go:embed frontend/dist/*
var embeddedFrontend embed.FS

func main() {
  // Initialize structured JSON logging for GCP
	jot.AutoSetup()
	port, err := ev.Get("API_PORT")
	if err != nil {
		port = "8080"
	}

	mux := http.NewServeMux()

	pingPath, pingHandler := pingv1connect.NewPingServiceHandler(&ping.Server{})
	mux.Handle(pingPath, pingHandler)

	frontendFS, err := fs.Sub(embeddedFrontend, "frontend/dist")
	if err != nil {
		jot.Fatal("failed to load embedded frontend filesystem", err)
	}
	mux.Handle("/", http.FileServer(http.FS(frontendFS)))

	h2s := &http2.Server{}
	server := &http.Server{
		Addr:    ":" + port,
		Handler: h2c.NewHandler(mux, h2s),
	}

	jot.Info("Starting CEPHLODYNE_APP_NAME server", "port", port)
	if err := server.ListenAndServe(); err != nil {
		jot.Fatal("Server crashed", err)
	}
}


-include .env
export

CONTRACTS_DIR ?= ../contracts

.PHONY: generate build-frontend run dev

generate:
	@echo "Generating code from central contracts..."
	buf generate $${CONTRACTS_DIR}/proto --template buf.gen.yaml

build-frontend: generate
	@echo "Installing and building frontend locally..."
	cd frontend && pnpm install && pnpm build

run: build-frontend
	@echo "Tidying and vendoring Go dependencies..."
	go mod tidy
	go mod vendor
	@echo "Starting production-like embedded server on port $${API_PORT}..."
	go run ./cmd/server/main.go

dev: generate
	@echo "Tidying and vendoring Go dependencies..."
	go mod tidy
	go mod vendor
	@echo "Ensuring frontend dist directory exists for go:embed..."
	mkdir -p frontend/dist && touch frontend/dist/.keep
	@echo "Starting rapid local development environment..."
	@echo "Go API running on http://localhost:$${API_PORT}"
	@bash -c "trap 'kill %1' SIGINT; go run -mod=vendor ./cmd/server/main.go & cd frontend && pnpm dev"


package ping

import (
	"context"
	"fmt"

	"connectrpc.com/connect"
	pingv1 "CEPHLODYNE_APP_NAME/internal/gen/ping/v1"
)

type Server struct{}

func (s *Server) Ping(
	ctx context.Context,
	req *connect.Request[pingv1.PingRequest],
) (*connect.Response[pingv1.PingResponse], error) {

	greeting := fmt.Sprintf("Hello %s, the mic-drop demo is a success!", req.Msg.Name)

	return connect.NewResponse(&pingv1.PingResponse{
		Message: greeting,
	}), nil
}


