package main

import (
	"context"
	"io/fs"
	"net/http"
	"os"

	"github.com/cephlodyne/kit/ev"
	"github.com/cephlodyne/kit/jot"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"

	"CEPHLODYNE_APP_NAME/frontend"
	"CEPHLODYNE_APP_NAME/internal/ping"
	pingv1connect "CEPHLODYNE_APP_NAME/internal/gen/ping/v1/pingv1connect"
)

func main() {
	ctx := context.Background()

	// Initialize structured JSON logging for GCP
	jot.AutoSetup()

	port, err := ev.Get("API_PORT")
	if err != nil {
		port = "8080"
	}

	mux := http.NewServeMux()

	pingPath, pingHandler := pingv1connect.NewPingServiceHandler(&ping.Server{})
	mux.Handle(pingPath, pingHandler)

	// Pull the embedded filesystem directly from the frontend package
	frontendFS, err := fs.Sub(frontend.FS, "dist")
	if err != nil {
		jot.CtxError(ctx, "failed to load embedded frontend filesystem", err)
		os.Exit(1)
	}
	mux.Handle("/", http.FileServer(http.FS(frontendFS)))

	h2s := &http2.Server{}
	server := &http.Server{
		Addr:    ":" + port,
		Handler: h2c.NewHandler(mux, h2s),
	}

	jot.CtxInfo(ctx, "Starting CEPHLODYNE_APP_NAME server", "port", port)
	if err := server.ListenAndServe(); err != nil {
		jot.CtxError(ctx, "Server crashed", err)
		os.Exit(1)
	}
}


