package main

import (
	"embed"
	"flag"
	"fmt"
	"hash/fnv"
	"io/fs"
	"os"
	"path/filepath"
	"strings"
)

// ==========================================
// MASTER VERSIONS (V2 Modernized)
// ==========================================
const (
	MasterGoVersion         = "1.26.4"
	MasterSvelteVersion     = "5.38.10"
	MasterViteVersion       = "7.1.5"
	MasterProtobufVersion   = "2.12.1"
	MasterConnectWebVersion = "2.1.2"
	MasterConnectGoVersion  = "1.18.1"
	MasterKitVersion        = "0.1.0"
)

//go:embed all:templates
var templatesFS embed.FS

func generatePort(appName string) string {
	h := fnv.New32a()
	h.Write([]byte(appName))
	port := 8000 + (h.Sum32() % 1000)
	return fmt.Sprintf("%d", port)
}

func main() {
	initCmd := flag.NewFlagSet("init", flag.ExitOnError)
	initType := initCmd.String("type", "", "Type ('external-web', 'internal-web', 'internal-api', 'contracts')")
	initUI := initCmd.String("ui", "svelte", "Frontend framework ('svelte', 'react', 'vue')")
	initContracts := initCmd.String("contracts", "../contracts", "Relative path to the protobuf contracts directory")

	if len(os.Args) < 2 {
		fmt.Println("Usage: ceph init --type=<type> <module-name>")
		os.Exit(1)
	}

	if os.Args[1] == "init" {
		initCmd.Parse(os.Args[2:])
		if initCmd.NArg() < 1 {
			fmt.Println("Error: Must specify a module name (e.g., cws-external).")
			os.Exit(1)
		}

		moduleName := initCmd.Arg(0)
		appPort := generatePort(moduleName)

		switch *initType {
		case "external-web", "internal-web":
			fmt.Printf("Scaffolding %s with %s UI for '%s' into current directory...\n", *initType, *initUI, moduleName)

			backendPath := fmt.Sprintf("templates/backends/%s", *initType)
			scaffoldTemplate(backendPath, ".", moduleName, appPort, *initContracts)

			frontendPath := fmt.Sprintf("templates/frontends/%s", *initUI)
			scaffoldTemplate(frontendPath, "./frontend", moduleName, appPort, *initContracts)

			fmt.Println("Done. Run 'make dev' to start.")

		case "internal-api":
			fmt.Printf("Scaffolding headless %s for '%s' into current directory...\n", *initType, moduleName)
			backendPath := fmt.Sprintf("templates/backends/%s", *initType)
			scaffoldTemplate(backendPath, ".", moduleName, appPort, *initContracts)
			fmt.Println("Done.")

		case "contracts":
			fmt.Printf("Scaffolding Contracts Repo '%s' into current directory...\n", moduleName)
			scaffoldTemplate("templates/contracts", ".", moduleName, "", "")
			fmt.Println("Done.")

		default:
			fmt.Println("Error: Unknown or missing --type.")
			os.Exit(1)
		}
	}
}

func scaffoldTemplate(templatePath string, targetDir string, moduleName string, appPort string, contractsDir string) {
	err := fs.WalkDir(templatesFS, templatePath, func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		// only process directories and .tmpl files
		if !d.IsDir() && !strings.HasSuffix(d.Name(), ".tmpl") {
			return nil // Skips .DS_Store, stray .env files, etc.
		}
		relPath, _ := filepath.Rel(templatePath, path)
		destPath := filepath.Join(targetDir, strings.TrimSuffix(relPath, ".tmpl"))

		if d.IsDir() {
			return os.MkdirAll(destPath, 0755)
		}

		data, err := templatesFS.ReadFile(path)
		if err != nil {
			return err
		}

		processed := string(data)
		processed = strings.ReplaceAll(processed, "CEPHLODYNE_APP_NAME", moduleName)
		processed = strings.ReplaceAll(processed, "{{API_PORT}}", appPort)
		processed = strings.ReplaceAll(processed, "{{CONTRACTS_DIR}}", contractsDir)
		processed = strings.ReplaceAll(processed, "{{GO_VERSION}}", MasterGoVersion)
		processed = strings.ReplaceAll(processed, "{{SVELTE_VERSION}}", MasterSvelteVersion)
		processed = strings.ReplaceAll(processed, "{{VITE_VERSION}}", MasterViteVersion)
		processed = strings.ReplaceAll(processed, "{{CONNECT_GO_VERSION}}", MasterConnectGoVersion)
		processed = strings.ReplaceAll(processed, "{{CONNECT_WEB_VERSION}}", MasterConnectWebVersion)
		processed = strings.ReplaceAll(processed, "{{PROTOBUF_VERSION}}", MasterProtobufVersion)
		processed = strings.ReplaceAll(processed, "{{KIT_VERSION}}", MasterKitVersion)

		return os.WriteFile(destPath, []byte(processed), 0644)
	})

	if err != nil {
		fmt.Printf("Error scaffolding template %s: %v\n", templatePath, err)
		os.Exit(1)
	}
}


package main

import (
	"bufio"
	"bytes"
	"encoding/json"
	"flag"
	"fmt"
	"os"
	"os/exec"
	"strings"
)

type Message struct {
	OSV *struct {
		ID      string `json:"id"`
		Summary string `json:"summary"`
		Details string `json:"details"`
	} `json:"osv"`
	Finding *struct {
		OSV          string `json:"osv"`
		FixedVersion string `json:"fixed_version"`
		Trace        []struct {
			Module string `json:"module"`
		} `json:"trace"`
	} `json:"finding"`
}

type OSVReport struct {
	Summary string
	Details string
}

// ModFix aggregates all vulnerabilities for a single module
type ModFix struct {
	FixedVersion string
	VulnIDs      map[string]bool
}

func main() {
	showDesc := flag.Bool("desc", false, "Show detailed vulnerability descriptions")
	flag.Parse()

	fmt.Println("🔄 Fetching the latest vulnerability database and scanner (govulncheck@latest)...")
	installCmd := exec.Command("go", "install", "golang.org/x/vuln/cmd/govulncheck@latest")
	installCmd.Stdout = os.Stdout
	installCmd.Stderr = os.Stderr
	if err := installCmd.Run(); err != nil {
		fmt.Printf("❌ Failed to update govulncheck: %v\n", err)
		fmt.Println("⚠️  Proceeding with cached version (if available)...")
	}

	fmt.Println("🔍 Running govulncheck... (this may take a moment)")
	cmd := exec.Command("govulncheck", "-json", "./...")
	out, _ := cmd.Output()

	reports := make(map[string]OSVReport)
	modulesToFix := make(map[string]*ModFix)

	decoder := json.NewDecoder(bytes.NewReader(out))
	for {
		var msg Message
		if err := decoder.Decode(&msg); err != nil {
			break
		}

		if msg.OSV != nil {
			reports[msg.OSV.ID] = OSVReport{
				Summary: msg.OSV.Summary,
				Details: msg.OSV.Details,
			}
		}

		if msg.Finding != nil && len(msg.Finding.Trace) > 0 {
			mod := msg.Finding.Trace[0].Module
			if mod != "" && mod != "stdlib" {
				if modulesToFix[mod] == nil {
					modulesToFix[mod] = &ModFix{
						FixedVersion: msg.Finding.FixedVersion,
						VulnIDs:      make(map[string]bool),
					}
				}
				// Ensure we capture a fixed version if the first finding lacked one
				if modulesToFix[mod].FixedVersion == "" && msg.Finding.FixedVersion != "" {
					modulesToFix[mod].FixedVersion = msg.Finding.FixedVersion
				}
				modulesToFix[mod].VulnIDs[msg.Finding.OSV] = true
			}
		}
	}

	if len(modulesToFix) == 0 {
		fmt.Println("✅ No third-party vulnerabilities found!")
		return
	}

	var mods []string
	for m := range modulesToFix {
		mods = append(mods, m)
	}

	fmt.Printf("\n⚠️  Found %d vulnerable modules:\n", len(mods))
	fmt.Println(strings.Repeat("-", 80))

	for i, m := range mods {
		fix := modulesToFix[m]

		if !*showDesc {
			// Clean, aggregated output
			fmt.Printf("[%d] %s (Fixes %d vulnerabilities -> update to %s)\n", i+1, m, len(fix.VulnIDs), fix.FixedVersion)
		} else {
			// Verbose output with full CVE descriptions
			fmt.Printf("[%d] %s (Update to %s)\n", i+1, m, fix.FixedVersion)
			for osvID := range fix.VulnIDs {
				fmt.Printf("    ↳ %s\n", osvID)
				rep := reports[osvID]
				if rep.Summary != "" {
					fmt.Printf("      Summary: %s\n", rep.Summary)
				}
				if rep.Details != "" {
					desc := strings.ReplaceAll(rep.Details, "\n", "\n      ")
					fmt.Printf("      Details: %s\n", desc)
				}
				fmt.Println()
			}
		}
	}
	fmt.Println(strings.Repeat("-", 80))

	if !*showDesc {
		fmt.Println("💡 Tip: Run 'govulnfix -desc' to see full vulnerability descriptions.")
	}

	fmt.Print("\nEnter numbers to fix (e.g., '1,3'), 'all' to fix all, or 'q' to quit: ")
	reader := bufio.NewReader(os.Stdin)
	input, _ := reader.ReadString('\n')
	input = strings.TrimSpace(input)

	if input == "q" || input == "" {
		fmt.Println("Aborted.")
		return
	}

	var selectedMods []string
	if input == "all" {
		selectedMods = mods
	} else {
		for p := range strings.SplitSeq(input, ",") {
			var idx int
			if _, err := fmt.Sscanf(strings.TrimSpace(p), "%d", &idx); err == nil {
				if idx > 0 && idx <= len(mods) {
					selectedMods = append(selectedMods, mods[idx-1])
				}
			}
		}
	}

	if len(selectedMods) == 0 {
		fmt.Println("No valid selection made. Aborting.")
		return
	}

	if len(selectedMods) == 0 {
		fmt.Println("No valid selection made. Aborting.")
		return
	}

	fmt.Println("\n🚀 Upgrading selected modules...")
	args := []string{"get"}
	for _, m := range selectedMods {
		args = append(args, m+"@latest")
	}
	runCmd("go", args...)

	fmt.Println("\n🧹 Cleaning up tracking files (go mod tidy)...")
	runCmd("go", "mod", "tidy")

	fmt.Println("\n📦 Rebuilding vendor fortress (go mod vendor)...")
	runCmd("go", "mod", "vendor")

	fmt.Println("\n✅ All done! Vulnerabilities patched and vendored.")
}

func runCmd(name string, args ...string) {
	cmd := exec.Command(name, args...)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	if err := cmd.Run(); err != nil {
		fmt.Printf("❌ Error running %s: %v\n", name, err)
	}
}
